import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm selects the next node by considering the least visited node across all trucks to minimize redundancy, 
    factoring in distance and truck load balance, else waits if the most distant node is approaching by any truck.}
    """
    # Step 1: Calculate the number of visits to each unvisited node by all trucks (excluding the current truck).
    visit_counts = {node: 0 for node in unvisited_nodes}
    for node in truck_nodes:
        if node in unvisited_nodes:
            visit_counts[node] += 1

    # Step 2: Find the node with the least visits that is not being targeted by another truck.
    candidate_nodes = [node for node in unvisited_nodes if visit_counts[node] == min(visit_counts.values())]

    # Step 3: Calculate distances from current_node to each candidate node and select the nearest one.
    if candidate_nodes:
        distances = [distance_matrix[current_node, node] for node in candidate_nodes]
        next_node = candidate_nodes[np.argmin(distances)]
    else:
        distances_to_unvisited = [distance_matrix[current_node, node] for node in unvisited_nodes]
        next_node = unvisited_nodes[np.argmin(distances_to_unvisited)]

    # Step 4: Check if another truck is currently moving towards the farthest node from the depot.
    # If so, return None to indicate waiting is optimal.
    farthest_nodes_sorted = sorted(unvisited_nodes, key=lambda node: distance_matrix[depot_node, node], reverse=True)
    for farthest_node in farthest_nodes_sorted:
        if farthest_node in truck_nodes:
            return None

    return next_node
